SELECT price
FROM price_records
WHERE product_id = 0 AND region_id = 0;

SELECT MAX(price) AS max_price
FROM price_records
WHERE product_id = 1 AND region_id = 1;

SELECT COUNT(*) AS total_price_changes
FROM price_change_records
WHERE year = 2013;

SELECT AVG(price) AS average_price
FROM price_records
WHERE product_id = 0 AND year = 2013;

SELECT MAX(price_change) AS max_price_change
FROM price_change_records
WHERE price_id = 0;
